create extension if not exists vector;
create extension if not exists pgcrypto;

create type user_role as enum ('admin', 'employee');
create type user_status as enum ('active', 'disabled');
create type assessment_status as enum ('in_progress', 'completed', 'abandoned');
create type message_role as enum ('system', 'assistant', 'user');

create table app_users ( id uuid primary key default gen_random_uuid(), employee_id uuid, username text unique, phone text unique, password_hash text not null, role user_role not null, status user_status not null default 'active', created_at timestamptz not null default now(), updated_at timestamptz not null default now() );
create table employees ( id uuid primary key default gen_random_uuid(), employee_no text not null unique, name text not null, phone text not null unique, email text, position text, position_description text, level text, created_at timestamptz not null default now(), updated_at timestamptz not null default now() );
alter table app_users add constraint app_users_employee_fk foreign key (employee_id) references employees(id);

create table employee_ai_profiles ( employee_id uuid primary key references employees(id), product_ability text, technical_ability text, project_experience text, profile_completion int not null default 0, updated_at timestamptz not null default now() );
create table assessment_sessions ( id uuid primary key default gen_random_uuid(), employee_id uuid not null references employees(id), status assessment_status not null default 'in_progress', current_round int not null default 0, total_rounds int not null default 10, started_at timestamptz not null default now(), completed_at timestamptz, abandoned_at timestamptz, abandoned_reason text );
create table assessment_messages ( id uuid primary key default gen_random_uuid(), session_id uuid not null references assessment_sessions(id), round_no int not null, role message_role not null, content text not null, created_at timestamptz not null default now() );
create table assessment_results ( id uuid primary key default gen_random_uuid(), session_id uuid not null unique references assessment_sessions(id), employee_id uuid not null references employees(id), score int not null check (score >= 0 and score <= 100), assessment_explanation text not null, structured_summary jsonb not null default '{}'::jsonb, is_latest boolean not null default false, created_at timestamptz not null default now() );

create table employee_embeddings ( id uuid primary key default gen_random_uuid(), employee_id uuid not null references employees(id), chunk_type text not null, content text not null, embedding vector(1024) not null, source_updated_at timestamptz not null default now(), created_at timestamptz not null default now() );
create table import_batches ( id uuid primary key default gen_random_uuid(), file_name text not null, imported_by uuid references app_users(id), status text not null default 'parsed', total_rows int not null default 0, success_rows int not null default 0, failed_rows int not null default 0, created_at timestamptz not null default now() );
create table import_rows ( id uuid primary key default gen_random_uuid(), batch_id uuid not null references import_batches(id), row_no int not null, employee_no text, raw_data jsonb not null, status text not null, error_message text, created_at timestamptz not null default now() );

create index idx_employees_employee_no on employees(employee_no);
create index idx_employees_phone on employees(phone);
create index idx_assessment_sessions_employee on assessment_sessions(employee_id);
create index idx_assessment_results_employee_latest on assessment_results(employee_id, is_latest);
create index idx_employee_embeddings_employee on employee_embeddings(employee_id);
create index idx_employee_embeddings_vector on employee_embeddings
using ivfflat (embedding vector_cosine_ops)
with (lists = 100);

export const maxDuration = 60;

export async function POST(request: Request) {
  const { sessionId, message } = await request.json();

  const user = await requireEmployeeSession();
  const session = await getAssessmentSession(sessionId);

  assertSessionBelongsToEmployee(session, user.employeeId);
  assertSessionInProgress(session);
  assertRoundLessOrEqualTen(session);

  await saveAssessmentMessage({
    sessionId,
    roundNo: session.current_round,
    role: 'user',
    content: message,
  });

  if (session.current_round < 10) {
    return streamNextQuestion(sessionId);
  }

  return streamFinalAssessmentResult(sessionId);
}

import { createOpenAICompatible } from '@ai-sdk/openai-compatible';

export const deepseek = createOpenAICompatible({
  name: 'deepseek',
  apiKey: process.env.DEEPSEEK_API_KEY,
  baseURL: process.env.DEEPSEEK_BASE_URL ?? 'https://api.deepseek.com',
});

import { streamText } from 'ai';
import { deepseek } from '@/lib/ai/deepseek';

const result = streamText({
  model: deepseek.chatModel(process.env.DEEPSEEK_MODEL ?? 'deepseek-v4-flash'),
  messages,
});

return result.toUIMessageStreamResponse();

